			wantErr: errors.New("clickhouse url not provided"),
		},
		{
			name:    "analytics flush period too low",
			path:    "./testdata/analytics/invalid_buffer_configuration_flush_period.yml",
			wantErr: errors.New("flush period below 10 seconds"),
		},
