{
	name: "advanced",
	path: "./testdata/advanced.yml",
	expected: func() *Config {
		cfg := Default()

		cfg.Audit = AuditConfig{
			Sinks: SinksConfig{
				LogFile: LogFileSinkConfig{
					Enabled: true,
					File:    "/path/to/logs.txt",
				},
			},
			Buffer: BufferConfig{
				Capacity:    10,
				FlushPeriod: 3 * time.Minute,
			},
			Events: []string{"*:*"},
		}

		cfg.Log = LogConfig{
			Level:     "WARN",
			File:      "testLogFile.txt",
			Encoding:  LogEncodingJSON,
			GRPCLevel: "ERROR",
			Keys: LogKeys{
				Time:    "time",
				Level:   "level",
				Message: "msg",
			},
		}
		cfg.Cors = CorsConfig{
			Enabled:        true,
			AllowedOrigins: []string{"foo.com", "bar.com", "baz.com"},
			AllowedHeaders: []string{"X-Some-Header", "X-Some-Other-Header"},
		}
		cfg.Cache.Enabled = true
		cfg.Cache.Backend = CacheMemory
		cfg.Cache.TTL = 1 * time.Minute
		cfg.Cache.Memory = MemoryCacheConfig{
			EvictionInterval: 5 * time.Minute,
		}
		cfg.Server = ServerConfig{
			Host:      "127.0.0.1",
			Protocol:  HTTPS,
			HTTPPort:  8081,
			HTTPSPort: 8080,
			GRPCPort:  9001,
			CertFile:  "./testdata/ssl_cert.pem",
			CertKey:   "./testdata/ssl_key.pem",
		}
		cfg.Tracing = TracingConfig{
			Enabled:  true,
			Exporter: TracingOTLP,
			Jaeger: JaegerTracingConfig{
				Host: "localhost",
				Port: 6831,
			},
			Zipkin: ZipkinTracingConfig{
				Endpoint: "http://localhost:9411/api/v2/spans",
			},
			OTLP: OTLPTracingConfig{
				Endpoint: "localhost:4318",
			},
		}
		cfg.Storage = StorageConfig{
			Type: GitStorageType,
			Git: &Git{
				Repository:   "https://github.com/flipt-io/flipt.git",
				Ref:          "production",
				PollInterval: 5 * time.Second,
				Authentication: Authentication{
					BasicAuth: &BasicAuth{
						Username: "user",
						Password: "pass",
					},
				},
			},
		}
		cfg.Database = DatabaseConfig{
			URL:                       "postgres://postgres@localhost:5432/flipt?sslmode=disable",
			MaxIdleConn:               10,
			MaxOpenConn:               50,
			ConnMaxLifetime:           30 * time.Minute,
			PreparedStatementsEnabled: true,
		}
		cfg.Meta = MetaConfig{
			CheckForUpdates:  false,
			TelemetryEnabled: false,
		}
		cfg.Authentication = AuthenticationConfig{
			Required: true,
			Session: AuthenticationSession{
				Domain:        "auth.flipt.io",
				Secure:        true,
				TokenLifetime: 24 * time.Hour,
				StateLifetime: 10 * time.Minute,
				CSRF: AuthenticationSessionCSRF{
					Key: "abcdefghijklmnopqrstuvwxyz1234567890", //gitleaks:allow
				},

